+            });
+
+            return {
+              success: true,
+              action: 'analyze',
+              total_patterns: allPatterns.length,
+              patterns: allPatterns.map((p) => {
+                try {
+                  const data = JSON.parse(p.value);
+                  return {
+                    modelId: data.modelId,
+                    pattern_type: data.pattern_type,
